Script.Source:
trace(logName, "Ascension-Subprocess-Market-Transfer start for identity: " + identityName);
addMessage(wfcontext, "Triggering workflow Ascension-Subprocess-Market-Transfer");
updateIdentityAttributesForRehire(identityName);

String auditString1 = "Identity that was rehired: "+identityName;
String auditString2 = "Market Transfer Flow is triggered";
String auditString3 = "Triggering the Rehire Workflow on the identity : "+identityName;
writeAuditRecordToIIQ("PersonaRehire", auditString1, auditString2, auditString3, identityName, "Persona Rehire");
addMessage(wfcontext, "Created workitem for review. WorkItem Name: Rehire - Market Transfer for user : " + identityDisplayName + " [" + identityName + "]");

if(wfcase.hasErrors()){
throw new RuntimeException("ERROR: in step - " + workflow.get("stepName") + " : " + wfcase.getErrors());
}
